import React from "react"
import { FormattedMessage, injectIntl } from "gatsby-plugin-intl"
import Player from "../components/musicPlayer";
import SEO from "../components/seo";
import CompetitionImg from "../images/2014_Oneness.jpg"
import CompetitionSong from "../sounds/Oneness_Competition_Snippet.mp3"
import GoodmanImg from "../images/Vocals_01.jpg"
import GoodmanSong from "../sounds/Goodman_Snippet.mp3"
import PrettyWordsImg from "../images/202001_Oneness_Treibsand_01.jpg"
import PrettyWordsSong from "../sounds/Pretty_Words_Snippet.mp3"
import HardRockImg from "../images/Vocals_02.jpg"
import HardRockSong from "../sounds/Oneness_Hard_Rock_Snippet.mp3"
import HeartbreakerImg from "../images/Keys_01.jpg"
import HeartbreakerSong from "../sounds/Heartbreaker_Snippet.mp3"

const songs = [
    {
        songTitle: "Goodman",
        btnId: "music-btn-05",
        audioId: "music05",
        audioSource: GoodmanSong,
        cardTitle: "Beach vibes!",
        cardInfo: "\"You can't keep a good man down!\"",
        cardImg: GoodmanImg,
        color: "success"
    }, {
        songTitle: "Pretty Words",
        btnId: "music-btn-02",
        audioId: "music02",
        audioSource: PrettyWordsSong,
        cardTitle: "\"Weißt du überhaupt!?\"",
        cardInfo: "Are they just pretty words, or is there a meaning behind them?",
        cardImg: PrettyWordsImg,
        color: "primary"
    }, {
        songTitle: "Heartbreaker",
        btnId: "music-btn-04",
        audioId: "music04",
        audioSource: HeartbreakerSong,
        cardTitle: "Sing along!",
        cardInfo: "\"Heartbreaker, She Call Me Heart-BREEEEEAAAAAKEER!\"",
        cardImg: HeartbreakerImg,
        color: "danger"
    },
    {
        songTitle: "Competition",
        btnId: "music-btn-01",
        audioId: "music01",
        audioSource: CompetitionSong,
        cardTitle: "\"Music is a Mission, not a Competition!\"",
        cardInfo: "For those who started out with music and ended up with greed.",
        cardImg: CompetitionImg,
        color: "secondary"
    }, {
        songTitle: "Hard Rock",
        btnId: "music-btn-03",
        audioId: "music03",
        audioSource: HardRockSong,
        cardTitle: "\"Don't Let Me Fall in the Fire!\"",
        cardInfo: "Happy tune about the hopes we have.",
        cardImg: HardRockImg,
        color: "success"
    },
];

const Music = ({intl}) => (
    <>
        <SEO title="Music"/>
        <div className="pb-3">
            <h3>Music</h3>
            <FormattedMessage id="music_sub"/>
        </div>
        <div className="row">
            {songs.map(song => (
                <div key={song.songTitle} className="col-sm-6">
                    <div className={"card text-white bg-" + song.color + " mb-3"}>
                        <div className="card-header">
                            <Player url={song.audioSource} color={song.color} title={song.songTitle}/>
                        </div>
                        <div className="card-body">
                            <h5 className="card-title">{song.cardTitle}</h5>
                            <p className="card-text">{song.cardInfo}</p>
                            <img src={song.cardImg} className="img-fluid rounded-lg" alt=""/>
                        </div>
                    </div>
                </div>
            ))}
        </div>
    </>
);

export default injectIntl(Music)